mapper.select:
SELECT  
  FROM  TB_SITE_LIST  A
 WHERE  A.SITE_ID = #{siteId}

mapper.insert:
INSERT  INTO TB_SITE_LIST
      ( SITE_ID
      , SITE_URL
      , SITE_NM
      , SITE_DC
      , SITE_THEMA_CL_CODE
      , ACTVTY_AT
      , USE_AT
      , FRST_REGIST_PNTTM
      , FRST_REGISTER_ID )
VALUES  ( #{siteId}
        , #{siteUrl}
        , #{siteNm}
        , #{siteDc}
        , #{siteThemaClCode}
        , #{actvtyAt}
        , #{useAt}
        , CURRENT_TIMESTAMP
        , #{frstRegisterId} )

mapper.update:
UPDATE  TB_SITE_LIST
   SET  SITE_URL           = #{siteUrl}
      , SITE_NM            = #{siteNm}
      , SITE_DC            = #{siteDc}
      , SITE_THEMA_CL_CODE = #{siteThemaClCode}
      , ACTVTY_AT          = #{actvtyAt}
      , USE_AT             = #{useAt}
      , LAST_UPDT_PNTTM    = CURRENT_TIMESTAMP
      , LAST_UPDUSR_ID     = #{lastUpdusrId}
 WHERE  SITE_ID = #{siteId}
